import anthropic
import json

client = anthropic.Anthropic()

# --- Tool implementations ---

def search(query: str) -> str:
    # Stub — replace with a real search API call
    return json.dumps({
        "results": [
            {"title": "Paris guide", "snippet": "Paris has 2.1M residents."},
        ]
    })

def calculate(expression: str) -> str:
    try:
        # Restrict to arithmetic only — no builtins accessible
        result = eval(expression, {"__builtins__": {}}, {})
        return json.dumps({"result": result})
    except Exception as exc:
        return json.dumps({"error": str(exc)})

def task_complete(answer: str) -> str:
    # This tool signals successful loop exit — the caller catches it
    return json.dumps({"done": True, "answer": answer})

# --- Dispatch table ---

DISPATCH: dict[str, callable] = {
    "search": search,
    "calculate": calculate,
    "task_complete": task_complete,
}

# --- Tool definitions for the API ---

TOOLS = [
    {
        "name": "search",
        "description": "Search for current information. Use before answering factual questions.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "calculate",
        "description": "Evaluate a Python arithmetic expression. No imports or function calls.",
        "input_schema": {
            "type": "object",
            "properties": {"expression": {"type": "string"}},
            "required": ["expression"],
        },
    },
    {
        "name": "task_complete",
        "description": "Call this exactly once when you have a complete final answer.",
        "input_schema": {
            "type": "object",
            "properties": {"answer": {"type": "string"}},
            "required": ["answer"],
        },
    },
]

def dispatch_action(block) -> str:
    """Dispatch a single tool_use block and return the result as a string."""
    fn = DISPATCH.get(block.name)
    if fn is None:
        return json.dumps({"error": f"Unknown tool: {block.name!r}"})
    try:
        return fn(**block.input)
    except TypeError as exc:
        return json.dumps({"error": f"Invalid arguments: {exc}"})
    except Exception as exc:
        return json.dumps({"error": str(exc)})

# Example usage in the agent loop
messages = [{"role": "user", "content": "What is twice the population of Paris in thousands?"}]

for _ in range(10):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=TOOLS,
        messages=messages,
    )
    messages.append({"role": "assistant", "content": resp.content})

    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    if not tool_calls:
        break

    results = [
        {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": dispatch_action(block),
        }
        for block in tool_calls
    ]
    messages.append({"role": "user", "content": results})

    # Check if task_complete was called
    for block in tool_calls:
        if block.name == "task_complete":
            print("Answer:", block.input["answer"])
            break

