# Hard constraints applied to every booking action
BANNED_AIRLINES = {"Spirit", "Frontier"}
MAX_PRICE_USD = 1000

class ValidationError(Exception):
    pass

def validate_flight_booking(airline: str, price: float, ticket_type: str) -> None:
    """Raise ValidationError if the booking violates a hard constraint."""
    if airline in BANNED_AIRLINES:
        raise ValidationError(f"Cannot book with {airline} — blocked airline.")
    if price > MAX_PRICE_USD:
        raise ValidationError(
            f"Price ${price:.2f} exceeds limit ${MAX_PRICE_USD}. "
            f"Ask the user for approval before proceeding."
        )
    if ticket_type == "non-refundable":
        raise ValidationError(
            "Non-refundable ticket requires explicit user confirmation. "
            "Ask the user before booking."
        )

def book_flight(airline: str, price: float, ticket_type: str) -> str:
    try:
        validate_flight_booking(airline, price, ticket_type)
    except ValidationError as exc:
        return json.dumps({"ok": False, "error": str(exc)})

    # Validation passed — proceed with the real booking
    return json.dumps({"ok": True, "booking_id": "BK-9001", "airline": airline})

# Test
print(book_flight("Spirit", 299.0, "refundable"))
# {"ok": false, "error": "Cannot book with Spirit — blocked airline."}

print(book_flight("Delta", 450.0, "non-refundable"))
# {"ok": false, "error": "Non-refundable ticket requires explicit user confirmation. ..."}

print(book_flight("Delta", 450.0, "refundable"))
# {"ok": true, "booking_id": "BK-9001", "airline": "Delta"}

