import json
import time

_SENT: set[str] = set()   # tracks idempotency keys for this process lifetime

def send_email_idempotent(
    to: str, subject: str, body: str, idempotency_key: str
) -> str:
    """
    Send an email at most once per idempotency_key.
    If the key was already used, return the cached success without re-sending.
    """
    if idempotency_key in _SENT:
        return json.dumps({"ok": True, "skipped": True, "reason": "already sent"})

    # Replace with a real email API call
    # smtp_client.send(to=to, subject=subject, body=body)
    _SENT.add(idempotency_key)
    return json.dumps({"ok": True, "skipped": False, "message_id": f"msg_{hash(idempotency_key) % 100000}"})

def dispatch_with_retry(fn, kwargs: dict, max_retries: int = 3) -> str:
    """Retry transient errors with exponential backoff. Do NOT use for non-idempotent actions."""
    delay = 1.0
    for attempt in range(max_retries):
        try:
            return fn(**kwargs)
        except (TimeoutError, ConnectionError) as exc:
            if attempt == max_retries - 1:
                return json.dumps({"error": f"Failed after {max_retries} retries: {exc}"})
            time.sleep(delay)
            delay *= 2
        except Exception as exc:
            # Permanent error — do not retry
            return json.dumps({"error": str(exc)})
    return json.dumps({"error": "unknown"})

